var e=JSON.parse(`[{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐야, 버터맨? 어울리지 않게 말도 없고.","JPN":"どうかしたの、バターマン？　無口だなんて、らしくないわよ。","ENG":"What's wrong, Sleazeball? You're strangely quiet.","TWN":"幹嘛啊，小白臉？一句話都不說，真不像你。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어제 만난 아가씨에게 차이기라도 했어?","JPN":"昨日会った娘に振られたとか？","ENG":"Did you get dumped by a lady you met last night?","TWN":"是被昨天遇見的小姐甩了喔？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하, 그런 정도로 힘이 빠져서야 제이크 실격이지.","JPN":"ハハ、俺がそれくらいで落ち込むわけないだろ。","ENG":"Hah hah. I'm Jake. Things like that don't let me down.","TWN":"哈哈，被甩了就垂頭喪氣的，沒資格當傑克·沃克吧。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"차였다는 건 새로운 사랑을 만날 기회라는 뜻 아니겠어?","JPN":"振られたということは、新しい恋を迎えるチャンスだしな？","ENG":"Besides, being dumped means that I have a new opportunity for love, right?","TWN":"被甩了不就意味著有了邂逅嶄新愛情的機會嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭔 헛소리야? 그럼 왜 그렇게 의욕 없는 표정을 하고 있는 건데?","JPN":"なに寝言言ってるの？\\nじゃあ、どうしてそんなにテンション低い顔をしてるわけ？","ENG":"Okay, then why do you look so unenthusiastic right now?","TWN":"說什麼鬼話啊？那你幹嘛一臉毫無幹勁的表情啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그냥...... 좀 지쳐서......","JPN":"なんとなく……ちょっと疲れちゃってな……","ENG":"I'm... I'm just tired.","TWN":"就這是……有些累了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지치다니, 뭐가?","JPN":"疲れる？　どうして？","ENG":"Tired of what?","TWN":"你竟然會說累，有什麼好累的？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"말하자면 좀 긴데 말이지......","JPN":"話すと長くなるんだが……","ENG":"It's a long story.","TWN":"這說來話長……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"내가 용병을 싫어한다고 이야기 했었던가?","JPN":"俺、傭兵が嫌いって話、したかな？","ENG":"Did I tell you that I hate mercenaries?","TWN":"我有說過我討厭傭兵嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"어라? 그랬나?","JPN":"あれ、そうだっけ？","ENG":"Huh? Do you?","TWN":"咦？有嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그러고 보니...... 그랬던 거 같기도 하고.","JPN":"言われてみれば……そんなこと聞いた気もする。","ENG":"Now that I think of it, yes, I think you said that before.","TWN":"這麼說來……好像真有這麼一回事。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"우리 집안은 원래 군인 집안이었거든.","JPN":"うちは代々軍人一家でな。","ENG":"I'm from a military family.","TWN":"我家以前是軍人家庭。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"할아버지만 해도 아주 전통적이고 고지식한 노병이었으니까.","JPN":"祖父はとても伝統的で生真面目なタイプの老兵だった。","ENG":"Everyone, including my grandpa, were traditional soldiers.","TWN":"雖然只有祖父是軍人，但他是非常傳統，而且固執的老兵。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하지만 관리실패가 벌어지고 대정화 전쟁이 벌어지면서......","JPN":"だが、管理失敗で大浄化戦争が勃発して……","ENG":"But when the Administration Failure happened, followed by the Grand Purification War,","TWN":"但發生管理失敗後，隨著淨化之戰的爆發……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"아버지는 군인이 아니라 용병이 되길 선택했어.","JPN":"父は軍人ではなく傭兵の道を選んだ。","ENG":"my dad chose to be a mercenary instead of a soldier.","TWN":"我父親沒有成為軍人，而是選擇成為了一個傭兵。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"알겠지만 그때는 전통적인 군인상 같은 게 통하던 시절이 아니었거든.","JPN":"知ってるだろうが、当時は伝統的な軍人像が通じるような時代じゃなかったんだ。","ENG":"As you know, traditional military virtues meant nothing at that time.","TWN":"我想妳也知道，在那個時代，傳統的軍人勳章並不是很吃香。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"할아버지는 아버지를 신념도 없이 돈만 밝히는 전쟁 장사꾼이라고 싫어했지만......","JPN":"祖父は父のことを信念もなく、ただただ金目当ての戦争屋だと蔑んだが……","ENG":"Grandpa called him a greedy opportunist that capitalized on the war for money.","TWN":"雖然祖父說父親是個毫無信念，眼裡都是錢的戰爭販子，非常討厭他……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"나는 그 정도는 아니었어. 일반적인 군인 가정보다 풍족하게 지낸 것도 사실이고.","JPN":"俺はそこまでじゃなかった。\\n一般的な軍人一家よりも豊かな暮らしをしていたのは事実だから。","ENG":"But I didn't hate him as much as Grandpa did. Because of my dad, we were better off than most military families, too.","TWN":"但我卻沒有厭惡到那種程度。那時我家的生活，比一般軍人家庭還要富裕，這也是事實。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......할아버지가 돌아가시기 전까지는 말이야.","JPN":"……祖父が亡くなるまではな。","ENG":"Then, my grandpa died.","TWN":"……直到祖父去世為止。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"할아버지가......?","JPN":"おじいさんが……？","ENG":"He did?","TWN":"你的祖父他？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래. 우리 가족이 살던 마을에 침식체들이 쳐들어 온 날,","JPN":"そうさ。俺の家族が暮らしていた村に侵食体が押し寄せてきた日、","ENG":"Yes. On the day that C.O.s invaded my village.","TWN":"沒錯。那天，侵蝕體入侵了我和家人生活的村莊。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"주 방위군의 방위라인이 뚫리자마자 계약했던 용병대들이 전부 철수해 버렸거든.","JPN":"州防衛軍の防衛線が破られるやいなや、\\n契約していた傭兵隊がこぞって撤退してしまってな。","ENG":"As soon as they penetrated the defense lines of the National Guard, all its hired mercenaries left.","TWN":"當時，州的防衛軍防線被突破後，有簽契約的傭兵部隊馬上就全部撤出了。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그 상황에서 공포에 질린 우리 가족과 마을사람들을 지킨 건......","JPN":"その時、恐怖に震える家族や村人たちを守ったのは……","ENG":"My family and everyone else in the village were left to our own devices,","TWN":"在那種情況下，保護了深陷恐懼中的家人，還有村裡人們的……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"창고에 굴러다니던 낡아빠진 라이플을 들고 달려온 할아버지였어.","JPN":"倉庫にほったらかしにしていた古いライフルを持って駆け付けた祖父だったんだ。","ENG":"and it was my grandpa who protected us with an old rifle he kept in storage.","TWN":"是從倉庫裡拿了一把陳舊步槍，跑過來的祖父。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"다행히 당시 대령이셨던 마리아 사령관님의 부대가 근처에 있어서 구조를 받긴 했지만.","JPN":"幸い、当時大佐だったマリア司令官の部隊が\\n近くに駐屯していたおかげで助かったが、","ENG":"Fortunately for us, Commander Maria, who was a colonel at that time, and her forces were nearby, and they came to our rescue.","TWN":"慶幸的是，當時還是大校的瑪麗亞司令官，她的部隊就在附近，所以我們得救了。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"전방에서 사람들과 함께 침식체를 막아내고 있던 할아버지는 이미......","JPN":"前方で人々とともに侵食体に立ち向かっていた祖父はすでに……","ENG":"But by the time they arrived, my grandpa, who had been fighting C.O.s alongside some others on the front line, was already...","TWN":"但在前方，和人們一起阻擋侵蝕體的祖父已經……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그때부턴 나도 할아버지의 의견에 동의를 했지.","JPN":"それ以降、俺も祖父の考えに同感するようになった。","ENG":"That made me agree with my grandpa.","TWN":"從那時開始，我也同意了爺爺的看法。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"용병이란 것들은 바퀴벌레처럼 살아남을 궁리만 하는 개자식들이고, 난 진짜 제대로 된 군인이 되겠다고.","JPN":"傭兵って奴ぁ、ゴキブリのように自分が生き延びることだけを考えるクズだ。\\n俺は真の軍人になってみせるってな。","ENG":"All mercenaries were selfish bastards who only look out for number one, and I wanted to become a real soldier.","TWN":"所謂的傭兵，就只是群像蟑螂一樣，只想著要活下去的傢伙，而我絕對要成為一個像樣的軍人。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래서 여기, 델타 세븐에 지원을 한 거야.","JPN":"だから、デルタセブンに志願したんだ。","ENG":"That's why I applied for Delta Seven.","TWN":"所以我志願來到第七三角洲部隊。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"관리 실패의 혼란을 수습하고 대 침식전 전투교리를 확립한 마리아 사령관님이라면......","JPN":"管理失敗の混乱を収拾して、対侵食戦の戦法を確立したマリア司令官なら……","ENG":"Commander Maria contained the chaos after the Administration Failure and established the anti-Corruption combat doctrines.","TWN":"如果是收拾了管理失敗的混亂，確立了對侵蝕戰守則的瑪麗亞司令官……"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"진짜 제대로 된, 시민들을 지키는 군인이 되는 방법을 가르쳐 줄 거라고 생각했거든.","JPN":"市民を守る、真の軍人になる方法を教えてくれると思ったから。","ENG":"I thought she could teach me how to become a real soldier and effectively protect civilians.","TWN":"一定能教會我，要怎麼成為一個真正像樣、能夠保護國民的軍人吧。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......그런데 생각했던 거랑은 많이 달랐나 보지?","JPN":"……けど、想像していたのとだいぶ違ったとか？","ENG":"But this isn't what you expected, is it?","TWN":"……然而，這和你想像的有很大的不同嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L46_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그래, 우리 모습을 보라고.","JPN":"まあな、俺らの現状を見てみろよ。","ENG":"No. Take a look at us.","TWN":"是啊，看看我們這副德性。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"대체 우리가 진행하는 이 <color=#ffd34c>전술 평가작전</color>이란 게 뭐지?","JPN":"俺らが展開するこの<color=#ffd34c>戦術評価作戦</color>は、\\nいったい何のためだ？","ENG":"What the hell is this <color=#ffd34c>tactical evaluation</color>? Why are we doing it?","TWN":"我們進行的這個<color=#ffd34c>戰術評估作戰</color>，到底是什麼東西啊？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"실전과 전혀 다를 바 없는 위험한 작전을 하면서도 정식 부대로 발령조차 받지 못하고 있어.","JPN":"実戦に匹敵する危険な作戦を展開するっつーのに、\\n正規部隊としての認定すらまだもらえてない。","ENG":"We've been carrying out operations just as dangerous as real missions, and yet we're not even a standing unit.","TWN":"雖然進行著和實戰沒什麼兩樣的危險作戰，但我們甚至沒有以正式部隊的身份接受過命令。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이래서야 누가 봐도 우리 부대를 싫어하는 파벌들의 정치적 견제일 뿐이잖아.","JPN":"これじゃあ誰がどう見ても、うちの部隊を目の敵にする勢力の\\n政治工作でしかないじゃないか。","ENG":"It's so clear we're caught in political crossfire.","TWN":"這不管誰來看，都是討厭我們部隊的派系在政治牽制吧。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"틀린 말은 아니긴 하네.","JPN":"確かに、一理あるわね。","ENG":"I have to agree.","TWN":"你說的也沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"용병들이 돈에 지배 받는 것처럼 군인들은 정치에 지배 받는 거니까.","JPN":"傭兵たちがお金に支配されるように、軍人は政治に支配されるから。","ENG":"Mercenaries are moved by money. Soldiers, by politics.","TWN":"就如同傭兵被金錢支配，軍人也會被政治所支配。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이런 실전도, 훈련도 아닌 국방부 장식품 노릇뿐이나 하려고 군인이 된 게 아닌데 말이야.","JPN":"実戦でもなく訓練でもない、こんな国防省の引き立て役をするために\\n軍人になったわけじゃないのにな。","ENG":"I'm tired of these missions that are neither real nor fake. I didn't join the Army just to increase its headcount, either.","TWN":"這種既不是實戰也不是訓練，只能算是國防部的裝飾品，我可不是為了這種事才當軍人的。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래서 그동안 철 지난 반항기 소년 흉내를 내고 다녔던 거야?","JPN":"だから、これまで第2次反抗期のようなマネをしていたわけ？","ENG":"Is that why you've been acting like a rebellious teenager?","TWN":"所以你這段時間，才一直模仿不懂事的叛逆期青少年？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하...... 그런 게 의외로 꽤 먹힌다고. 유행타지 않는 스타일이랄까?","JPN":"ハハ……ああいうのは案外都合がいいんだよ。時代問わず使えるというか？","ENG":"Hah hah. You know that actually works. It's even timeless.","TWN":"哈哈……這種類型還意外地受歡迎，算是不趕流行的類型？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"단호하게 충고하는데, 난 별로야.","JPN":"強く言っておくけど、アタシはイマイチだと思うわ。","ENG":"Let me assert my firm belief: I don't like it.","TWN":"真誠地給你個忠告，我覺得不行。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"허세는 멍청함의 척도라고. 차라리 지금처럼 솔직한 게 훨씬 나아.","JPN":"虚勢を張るのは愚かな証拠よ。\\nむしろ、今のように素直なほうがずっと良いと思う。","ENG":"Only stupid people bluff. I like you much better when you're being honest like this.","TWN":"裝腔作勢只會讓別人覺得你愚蠢，不如和現在一樣坦率會比較好。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"그런가?","JPN":"そうか？","ENG":"Do you?","TWN":"是嗎？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"좋은 충고 고마워. 기억해 둬야겠네.","JPN":"良い忠告をありがとう。覚えておくよ。","ENG":"Thank you for your advice. I'll remember it.","TWN":"謝謝妳的良心建議。我會記住的。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"어쨌든...... 내가 너무 순진했던 걸지도 모르지.","JPN":"まあ……俺が安直過ぎたのかもしれない。","ENG":"Anyway, maybe I was naive.","TWN":"但說不定……是我太天真了。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"시대가 변했다는 걸 인정해야 할 때가 온 걸지도 몰라.","JPN":"時代の変化を、素直に認めるべき時が来たのかもな。","ENG":"Maybe it's time I accept that things have changed.","TWN":"也許是時候該承認，時代已經變了。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"적어도 침식체에 맞서 사람들을 지키는 건, 이제 군인이 아닌 용병들의 일인 것 같으니까.","JPN":"少なくとも侵食体に立ち向かって人間を守るのは、\\nもはや軍人ではなく傭兵の仕事になっているみだいだからな。","ENG":"Or at least that it's now mercenaries who protect people against C.O.s instead of us soldiers.","TWN":"至少現在對抗侵蝕體、保護人類的，似乎不再是軍人，而是傭兵了。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"맘에 들진 않지만 그 자식들 사이에 내 자리가 있을지도 모르지.","JPN":"気に食わないけど、あいつらのところに俺のポジションがあるかもしれんな。","ENG":"I don't like that, but maybe my place is among them.","TWN":"雖然不太想承認，不過那群傢伙之間，說不定也有我的位置。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐...... 용병이라고 해도 사람마다 다른 거 아니겠어?","JPN":"まあ傭兵とはいっても一概には言えないからね？","ENG":"Well, not all mercenaries are the same.","TWN":"什麼……就算都是傭兵，但每個人都不一樣吧？"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"너라면 용병이 되더라도 잘 해나갈 수 있을 거야.","JPN":"君なら傭兵になってもうまくやっていけると思うわ。","ENG":"I'm sure you'll make a good mercenary.","TWN":"你如果當了傭兵，應該也會當得有聲有色。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"그래도 힘들면 이야기하라고. 넋두리 정도는 들어줄 테니까.","JPN":"それでも大変な時は言ってよ。愚痴ぐらいは聞いてあげるから。","ENG":"But if the going gets tough, you let me know. I'm a good listener.","TWN":"如果你還是覺得累，那就和我說說吧。只是發牢騷的話，我會聽你說的。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"하하. 너도 침식체 상대하다가 힘들면 이 오빠에게 부탁하라고. 그런 건 내 전문이니까.","JPN":"ハハ、君も侵食体相手に疲れてしまったら、このお兄ちゃんに頼りなさい。\\nそういうのは俺の専門だからな。","ENG":"Hah hah. Okay, and if you have a hard time fighting C.O.s, just call for your big brother. I've got your back.","TWN":"哈哈，妳也是啊。如果妳對上侵蝕體覺得很吃力的話，就來依靠一下我這個哥哥吧。畢竟這是我的專長。"},"stage":{"bg":"WORKSHOP","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_SYS_RUNNING"},{"id":"L19_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하! 오빠 같은 소리 하네.","JPN":"ふん！　誰がお兄ちゃんよ。","ENG":"Ha! Big brother, my butt!","TWN":"哈！什麼哥哥啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"솔직히 말해 봐. 너 평소에 두리안만 까먹고 살지?","JPN":"正直に言いなさいよ。君、普段ドリアンばかり食べてない？","ENG":"Seriously, what's wrong with you?","TWN":"說實話，你平時是不是只吃榴槤啊。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"느끼해 빠져서는......","JPN":"そのぬめっとした感じ、間違いないわ……","ENG":"You're so cheesy and corny.","TWN":"這麼油膩……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"으앗?!","JPN":"わあっ！？","ENG":"Wah!","TWN":"嗚啊？！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L23_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"깜짝이야.","JPN":"びっくりしたぁ。","ENG":"Geez!","TWN":"嚇我一跳。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_THUNDER"},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이 소리는......설마?","JPN":"この音は、まさか……？","ENG":"This noise? Oh, no.","TWN":"這個聲音……難道？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_EARTHQUAKE"}]`);export{e as default};